function counter() {
  let count = 0;
  return function () {
    count++;
    return count;
  };
}

const increment = counter();
console.log(increment()); // 1
console.log(increment()); // 2
console.log(increment()); // 3 — count ভ্যারিয়েবলটি 'মনে' থাকে

const car = {
  brand: "টয়োটা",
  showBrand() {
    console.log(this.brand); // 'this' এখানে car অবজেক্টকে নির্দেশ করে
  }
};
car.showBrand(); // টয়োটা

class Animal {
  constructor(name, sound) {
    this.name = name;
    this.sound = sound;
  }
  makeSound() {
    console.log(`${this.name} বলছে: ${this.sound}`);
  }
}

class Dog extends Animal {
  constructor(name) {
    super(name, "ঘেউ ঘেউ");
  }
  fetch() {
    console.log(`${this.name} বল আনছে!`);
  }
}

const myDog = new Dog("বাদশা");
myDog.makeSound(); // বাদশা বলছে: ঘেউ ঘেউ
myDog.fetch();     // বাদশা বল আনছে!
